import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Login from './pages/Login';
import Register from './pages/Register';
import Profile from './pages/Profile';
import Tours from './pages/Tours'; // 1. 把 Tasks 改成 Tours
import { AuthProvider } from './context/AuthContext'; // 2. 引入 Auth
import { TourProvider } from './context/TourContext'; // 3. 引入我們剛寫的 TourContext

function App() {
  return (
    <AuthProvider>
      <TourProvider>
        <Router>
          <Navbar />
          <Routes>
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />
            <Route path="/profile" element={<Profile />} />
            {/* 4. 修改路徑名稱，這會讓網址變成 localhost:3000/tours */}
            <Route path="/tours" element={<Tours />} />
            <Route path="/" element={<Tours />} /> {/* 設定首頁直接看行程 */}
          </Routes>
        </Router>
      </TourProvider>
    </AuthProvider>
  );
}

export default App;
